def count_nums(arr):
    def sum_of_digits(n):
        total = 0
        negative = n < 0
        n = abs(n)
        while n:
            total += n % 10
            n //= 10
        if negative:
            total -= 2 * (abs(n) % 10)
        return total

    return sum(1 for num in arr if sum_of_digits(num) > 0)
